import { Given, When, Then } from '@cucumber/cucumber';
import { expect } from '@playwright/test';
import { ConsentPage } from '../pages/ConsentPage';
import { ConsentSettingsPage } from '../pages/ConsentSettingsPage';
import { ApiClient } from '../support/ApiClient';

let consentPage: ConsentPage;
let consentSettingsPage: ConsentSettingsPage;
let apiClient: ApiClient;
let apiResponse: any;

Given('I have no prior CRA consent', async function () {
  apiClient = new ApiClient(this.authToken);
  const consents = await apiClient.getConsents(this.customerId);
  expect(consents.data.length).toBe(0);
});

Given('I already have active EXPERIAN consent', async function () {
  apiClient = new ApiClient(this.authToken);
  const consents = await apiClient.getConsents(this.customerId);
  const active = consents.data.find((c: any) => c.craProvider === 'EXPERIAN' && c.status === 'GRANTED');
  expect(active).toBeTruthy();
});

Given('my consent has already been withdrawn', async function () {
  apiClient = new ApiClient(this.authToken);
  const consents = await apiClient.getConsents(this.customerId);
  const withdrawn = consents.data.find((c: any) => c.status === 'WITHDRAWN');
  expect(withdrawn).toBeTruthy();
});

Given('the consent text version has been updated to {string}', async function (version: string) {
  this.expectedConsentVersion = version;
});

When('I navigate to the Credit Coach', async function () {
  consentPage = new ConsentPage(this.page);
  await consentPage.navigate();
});

When('I tick all consent checkboxes', async function () {
  await consentPage.tickAllCheckboxes();
});

When('I tick only the first two checkboxes', async function () {
  await consentPage.tickCheckbox(0);
  await consentPage.tickCheckbox(1);
});

When('I tap {string}', async function (buttonText: string) {
  await this.page.getByRole('button', { name: buttonText }).click();
});

When('I attempt to grant EXPERIAN consent again', async function () {
  apiClient = new ApiClient(this.authToken);
  apiResponse = await apiClient.grantConsent({
    craProvider: 'EXPERIAN',
    consentTextVersion: '1.0',
    consentTextHash: 'abc123',
    channel: 'IOS',
    privacyNoticeAccepted: true
  });
});

When('I navigate to Settings > Credit Coach > Manage Consent', async function () {
  consentSettingsPage = new ConsentSettingsPage(this.page);
  await consentSettingsPage.navigate();
});

When('I confirm the withdrawal with reason {string}', async function (reason: string) {
  await consentSettingsPage.confirmWithdrawal(reason);
});

When('I attempt to withdraw consent again', async function () {
  apiClient = new ApiClient(this.authToken);
  apiResponse = await apiClient.withdrawConsent(this.consentId, 'customer_request');
});

Then('I see the consent screen with transparency disclosures', async function () {
  await expect(consentPage.disclosureSection).toBeVisible();
});

Then('the disclosures include {string}, {string}, {string}, {string}', async function (d1: string, d2: string, d3: string, d4: string) {
  const text = await consentPage.getDisclosureText();
  expect(text).toContain(d1);
  expect(text).toContain(d2);
  expect(text).toContain(d3);
  expect(text).toContain(d4);
});

Then('no checkboxes are pre-ticked', async function () {
  const states = await consentPage.getCheckboxStates();
  states.forEach(state => expect(state).toBe(false));
});

Then('the consent API returns status {int}', async function (status: number) {
  expect(apiResponse.status).toBe(status);
});

Then('the consent record includes timestamp and consent text version {string}', async function (version: string) {
  const body = await apiResponse.json();
  expect(body.data.grantedAt).toBeTruthy();
  expect(body.data.consentTextVersion).toBe(version);
});

Then('a {string} event is published', async function (eventName: string) {
  // Verify via test event listener or Pub/Sub subscription
  const events = await apiClient.getRecentEvents(eventName);
  expect(events.length).toBeGreaterThan(0);
});

Then('the {string} button is disabled', async function (buttonText: string) {
  const button = this.page.getByRole('button', { name: buttonText });
  await expect(button).toBeDisabled();
});

Then('the consent status is {string} with withdrawnAt timestamp', async function (status: string) {
  const body = await apiResponse.json();
  expect(body.data.status).toBe(status);
  expect(body.data.withdrawnAt).toBeTruthy();
});

import { Given, When, Then } from '@cucumber/cucumber';
import { expect } from '@playwright/test';
import { DashboardPage } from '../pages/DashboardPage';
import { ApiClient } from '../support/ApiClient';

let dashboardPage: DashboardPage;
let apiClient: ApiClient;
let apiResponse: any;
let startTime: number;

Given('I have active EXPERIAN consent', async function () {
  apiClient = new ApiClient(this.authToken);
  const consents = await apiClient.getConsents(this.customerId);
  const active = consents.data.find((c: any) => c.craProvider === 'EXPERIAN' && c.status === 'GRANTED');
  expect(active).toBeTruthy();
});

Given('I have no active CRA consent', async function () {
  // Ensure no active consent exists for test customer
});

Given('the CRA API is configured to timeout after 2.5 seconds', async function () {
  await apiClient.configureCraStub({ timeout: 2500 });
});

Given('the CRA API is unavailable', async function () {
  await apiClient.configureCraStub({ unavailable: true });
});

Given('a cached score of {int} exists', async function (score: number) {
  await apiClient.seedCachedScore(this.customerId, score);
});

Given('a cached score of {int} from {string} exists', async function (score: number, date: string) {
  await apiClient.seedCachedScore(this.customerId, score, date);
});

Given('no cached score exists', async function () {
  await apiClient.clearCachedScore(this.customerId);
});

Given('I have already refreshed my score today', async function () {
  await apiClient.refreshScore(this.customerId);
});

Given('my current score is {int} with previous score {int}', async function (current: number, previous: number) {
  await apiClient.seedScore(this.customerId, current, previous);
});

Given('this is my first score retrieval with no previous score', async function () {
  await apiClient.seedFirstScore(this.customerId);
});

Given('the CRA returns score but no factors', async function () {
  await apiClient.configureCraStub({ partialResponse: true });
});

Given('the circuit breaker has tripped after 3 consecutive failures', async function () {
  await apiClient.configureCraStub({ tripCircuitBreaker: true });
});

When('I navigate to the Credit Coach dashboard', async function () {
  startTime = Date.now();
  dashboardPage = new DashboardPage(this.page);
  await dashboardPage.navigate();
});

When('I request my credit score via API', async function () {
  apiClient = new ApiClient(this.authToken);
  apiResponse = await apiClient.getScore(this.customerId);
});

When('I attempt another on-demand refresh', async function () {
  apiResponse = await apiClient.refreshScore(this.customerId);
});

Then('the score is retrieved via soft search', async function () {
  await dashboardPage.waitForScoreLoaded();
  expect(await dashboardPage.isScoreVisible()).toBe(true);
});

Then('the response is received within {int} seconds', async function (seconds: number) {
  const elapsed = Date.now() - startTime;
  expect(elapsed).toBeLessThan(seconds * 1000);
});

Then('the score, band, and factors are stored', async function () {
  const score = await apiClient.getScore(this.customerId);
  expect(score.data.score).toBeTruthy();
  expect(score.data.band).toBeTruthy();
});

Then('the cached score {int} is displayed', async function (score: number) {
  await dashboardPage.waitForScoreLoaded();
  expect(await dashboardPage.getScoreValue()).toBe(score.toString());
});

Then('the response header {string} is {string}', async function (header: string, value: string) {
  const response = await apiClient.getScoreRaw(this.customerId);
  expect(response.headers.get(header.toLowerCase())).toBe(value);
});

Then('a {string} timestamp is shown', async function (label: string) {
  expect(await dashboardPage.hasStaleIndicator()).toBe(true);
});

Then('the API returns status {int}', async function (status: number) {
  expect(apiResponse.status).toBe(status);
});

Then('the error indicates consent is required', async function () {
  const body = await apiResponse.json();
  expect(body.title).toContain('consent');
});

Then('the {string} header indicates remaining wait time', async function (header: string) {
  expect(apiResponse.headers.get(header.toLowerCase())).toBeTruthy();
});

Then('I see my score {string} on the gauge widget', async function (score: string) {
  expect(await dashboardPage.getScoreValue()).toBe(score);
});

Then('I see the band {string}', async function (band: string) {
  expect(await dashboardPage.getBandLabel()).toContain(band);
});

Then('I see the change {string}', async function (change: string) {
  expect(await dashboardPage.getChangeText()).toContain(change);
});

Then('the score is labelled {string}', async function (label: string) {
  expect(await dashboardPage.getProviderLabel()).toContain(label);
});

Then('the change section shows {string}', async function (message: string) {
  expect(await dashboardPage.getChangeText()).toContain(message);
});

