import { Page, Locator, expect } from '@playwright/test';

export class ConsentPage {
  readonly page: Page;
  readonly disclosureSection: Locator;
  readonly checkboxes: Locator;
  readonly agreeButton: Locator;
  readonly notNowButton: Locator;

  constructor(page: Page) {
    this.page = page;
    this.disclosureSection = page.locator('[data-testid="consent-disclosures"]');
    this.checkboxes = page.locator('input[type="checkbox"]');
    this.agreeButton = page.getByRole('button', { name: /Agree & Check My Score/i });
    this.notNowButton = page.getByRole('button', { name: /Not now/i });
  }

  async navigate() {
    await this.page.goto('/credit-coach/consent');
    await this.page.waitForLoadState('networkidle');
  }

  async getDisclosureText(): Promise<string> {
    return await this.disclosureSection.textContent() || '';
  }

  async getCheckboxStates(): Promise<boolean[]> {
    const count = await this.checkboxes.count();
    const states: boolean[] = [];
    for (let i = 0; i < count; i++) {
      states.push(await this.checkboxes.nth(i).isChecked());
    }
    return states;
  }

  async tickAllCheckboxes() {
    const count = await this.checkboxes.count();
    for (let i = 0; i < count; i++) {
      await this.checkboxes.nth(i).check();
    }
  }

  async tickCheckbox(index: number) {
    await this.checkboxes.nth(index).check();
  }
}

import { Page, Locator } from '@playwright/test';

export class ConsentSettingsPage {
  readonly page: Page;
  readonly withdrawButton: Locator;
  readonly confirmButton: Locator;
  readonly statusBadge: Locator;

  constructor(page: Page) {
    this.page = page;
    this.withdrawButton = page.getByRole('button', { name: /Withdraw Consent/i });
    this.confirmButton = page.getByRole('button', { name: /Confirm/i });
    this.statusBadge = page.locator('[data-testid="consent-status"]');
  }

  async navigate() {
    await this.page.goto('/credit-coach/settings/consent');
    await this.page.waitForLoadState('networkidle');
  }

  async confirmWithdrawal(reason: string) {
    await this.withdrawButton.click();
    await this.page.selectOption('[data-testid="withdrawal-reason"]', reason);
    await this.confirmButton.click();
  }
}

import { Page, Locator, expect } from '@playwright/test';

export class DashboardPage {
  readonly page: Page;
  readonly scoreValue: Locator;
  readonly scoreBand: Locator;
  readonly scoreChange: Locator;
  readonly providerLabel: Locator;
  readonly staleIndicator: Locator;
  readonly refreshButton: Locator;
  readonly factorsSection: Locator;
  readonly seeAllLink: Locator;
  readonly changeSection: Locator;
  readonly loadingSkeleton: Locator;

  constructor(page: Page) {
    this.page = page;
    this.scoreValue = page.locator('[data-testid="score-value"]');
    this.scoreBand = page.locator('[data-testid="score-band"]');
    this.scoreChange = page.locator('[data-testid="score-change"]');
    this.providerLabel = page.locator('[data-testid="provider-label"]');
    this.staleIndicator = page.locator('[data-testid="stale-indicator"]');
    this.refreshButton = page.getByRole('button', { name: /Try Again|Refresh/i });
    this.factorsSection = page.locator('[data-testid="factors-section"]');
    this.seeAllLink = page.getByRole('link', { name: /See all/i });
    this.changeSection = page.locator('[data-testid="change-explanation"]');
    this.loadingSkeleton = page.locator('[data-testid="loading-skeleton"]');
  }

  async navigate() {
    await this.page.goto('/credit-coach/dashboard');
  }

  async waitForScoreLoaded() {
    await this.scoreValue.waitFor({ state: 'visible', timeout: 5000 });
  }

  async isScoreVisible(): Promise<boolean> {
    return await this.scoreValue.isVisible();
  }

  async getScoreValue(): Promise<string> {
    return await this.scoreValue.textContent() || '';
  }

  async getBandLabel(): Promise<string> {
    return await this.scoreBand.textContent() || '';
  }

  async getChangeText(): Promise<string> {
    return await this.scoreChange.textContent() || '';
  }

  async getProviderLabel(): Promise<string> {
    return await this.providerLabel.textContent() || '';
  }

  async hasStaleIndicator(): Promise<boolean> {
    return await this.staleIndicator.isVisible();
  }
}

import { Page, Locator } from '@playwright/test';

export class ConversationPage {
  readonly page: Page;
  readonly chatInput: Locator;
  readonly sendButton: Locator;
  readonly messages: Locator;
  readonly quickReplies: Locator;

  constructor(page: Page) {
    this.page = page;
    this.chatInput = page.locator('[data-testid="chat-input"]');
    this.sendButton = page.getByRole('button', { name: /Send message/i });
    this.messages = page.locator('[data-testid="chat-message"]');
    this.quickReplies = page.locator('[data-testid="quick-reply"]');
  }

  async navigate() {
    await this.page.goto('/credit-coach/conversation');
    await this.page.waitForLoadState('networkidle');
  }

  async sendMessage(text: string) {
    await this.chatInput.fill(text);
    await this.sendButton.click();
  }

  async waitForResponse(): Promise<string> {
    const lastMsg = this.page.locator('[data-testid="assistant-message"]').last();
    await lastMsg.waitFor({ state: 'visible', timeout: 10000 });
    return await lastMsg.textContent() || '';
  }
}
